#!/usr/bin/env node
import { mkdir, writeFile } from 'node:fs/promises';
import path from 'node:path';

const args = new Map();
for (let index = 2; index < process.argv.length; index += 2) {
  args.set(process.argv[index], process.argv[index + 1]);
}

const phase = args.get('--phase') ?? 'PHASE-01A';
const workspace = args.get('--workspace');
if (!workspace) {
  process.stderr.write('Missing --workspace\n');
  process.exit(1);
}

await mkdir(path.join(workspace, 'docs'), { recursive: true });
await writeFile(
  path.join(workspace, 'docs', 'fake-agent-output.md'),
  ['# Fake Agent Output', '', `Phase: ${phase}`, '', 'Generated by the package-local fake executor.', ''].join('\n'),
);

const report = {
  schemaVersion: 1,
  phase,
  status: 'pass',
  summary: 'Fake executor wrote a deterministic docs artifact.',
  filesChanged: ['docs/fake-agent-output.md'],
  commandsRun: [{ command: 'git diff --check', status: 'pass' }],
  tasksCompleted: ['task-001'],
  cursorTasks: [],
  gaps: [],
};

process.stdout.write(`Fake executor report\n\n\`\`\`json\n${JSON.stringify(report, null, 2)}\n\`\`\`\n`);
